  display: flex;
  align-items: center;
  gap: 4px;
  flex-wrap: wrap;
}
.breadcrumb a {
  color: #9a9a9a;
  font-size: 13px;
}
.breadcrumb a:hover {
  color: #e6e6e6;
  text-decoration: none;
}

