  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}
.toolbar label.btn:focus-within {
  outline: 2px solid #6aa6ff;
  outline-offset: 2px;
